module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0] dout_parallel,
    output reg dout_valid
);

    reg [7:0] shift_reg;
    reg [3:0] counter;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            shift_reg <= 8'b00000000;
            counter <= 4'b0000;
            dout_parallel <= 8'b00000000;
            dout_valid <= 1'b0;
        end
        else begin
            if (din_valid) begin
                shift_reg <= {shift_reg[6:0], din_serial};
                counter <= counter + 1;
            end

            if (counter == 4'b1000) begin
                dout_parallel <= shift_reg;
                dout_valid <= 1'b1;
                counter <= 4'b0000;
            end
            else begin
                dout_valid <= 1'b0;
            end
        end
    end

endmodule
